solution:
def is_well_formed(xml):
    stack = []
    i = 0
    while True:
        start = xml.find('<', i)
        if start == -1:
            break
        end = xml.find('>', start)
        if end == -1:
            return False
        tag = xml[start+1:end].strip()
        if not tag:
            return False
        if tag.startswith('/'):
            name = tag[1:]
            if not stack or stack[-1] != name:
                return False
            stack.pop()
        else:
            # pomijamy self-closing tutaj (zakładamy brak)
            stack.append(tag)
        i = end + 1
    return len(stack) == 0

