def get_column(rows, index):
    result = []
    # jeśli brak wierszy lub tylko nagłówek, zwracamy pustą listę
    if len(rows) <= 1:
        return result
    for i in range(1, len(rows)):
        row = rows[i]
        # jeśli wiersz jest krótki, pomiń go
        if index < len(row):
            result.append(row[index])
    return result

def unique_artists(rows):
    artists = []
    if len(rows) <= 1:
        return artists
    for i in range(1, len(rows)):
        row = rows[i]
        if len(row) >= 2:
            artist = row[1]
            if artist not in artists:
                artists.append(artist)
    return artists

def validate_row_types(header_types, row):
    if len(row) != len(header_types):
        return False
    for i in range(len(header_types)):
        t = header_types[i]
        val = row[i]
        if t == 'str':
            # każda wartość traktujemy jako string, więc OK
            continue
        elif t == 'int':
            # sprawdzamy czy tekst to liczba całkowita
            if not isinstance(val, str) or not val.isdigit():
                return False
        else:
            # nieznany typ w nagłówku - uznajemy za niezgodność
            return False
    return True
